// Fetch the prior week's coaching themes + agent names from Supabase
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://YOUR_SUPABASE_PROJECT.supabase.co/rest/v1';
const hdr = { apikey };

// Get the Monday of last week
const now = new Date();
const dayOfWeek = now.getUTCDay();
const lastMonday = new Date(now);
lastMonday.setUTCDate(now.getUTCDate() - 7 - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
const weekStart = lastMonday.toISOString().slice(0, 10);

const [themesResp, agentsResp] = await Promise.all([
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/coaching_themes_weekly?week_start_date=eq.${weekStart}&order=tier.asc,severity.desc`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: 'GET',
    url: `${base}/agents?select=id,name,site&is_active=eq.true`,
    headers: hdr,
    json: true,
  }),
]);

if (!Array.isArray(themesResp) || themesResp.length === 0) {
  return [{ json: { weekStart, hasThemes: false, message: 'No coaching themes for last week.' } }];
}

const nameMap = {};
for (const a of agentsResp) nameMap[a.id] = { name: a.name, site: a.site };

// Group by agent, max 3 per agent, sorted by tier then severity
const byAgent = {};
for (const t of themesResp) {
  const agent = nameMap[t.agent_id];
  if (!agent) continue;
  const key = agent.name;
  if (!byAgent[key]) byAgent[key] = { name: agent.name, site: agent.site, themes: [] };
  if (byAgent[key].themes.length < 3) {
    byAgent[key].themes.push({
      label: t.theme_label,
      severity: t.severity,
      tier: t.tier,
      action: t.suggested_action,
      agentValue: t.agent_value,
      benchmarkValue: t.benchmark_value,
    });
  }
}

// Build Slack blocks
const sevEmoji = { high: '🔴', med: '🟡', low: '🔵' };
const tierLabel = { 1: 'Process', 2: 'Behavioral', 3: 'Strategic' };

const blocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: `🧠 Weekly Coaching Digest — ${weekStart}` },
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*${Object.keys(byAgent).length} agents* with coaching themes this week. Top 3 themes per agent, ordered by impact.` },
  },
  { type: 'divider' },
];

const agents = Object.values(byAgent).sort((a, b) => {
  // Sort by highest severity first
  const sevOrd = { high: 3, med: 2, low: 1 };
  const aMax = Math.max(...a.themes.map(t => sevOrd[t.severity] || 0));
  const bMax = Math.max(...b.themes.map(t => sevOrd[t.severity] || 0));
  return bMax - aMax;
});

for (const agent of agents) {
  const themeLines = agent.themes.map(t => {
    const emoji = sevEmoji[t.severity] || '⚪';
    const tier = tierLabel[t.tier] || 'Unknown';
    let line = `${emoji} *${t.label}* (${tier})`;
    if (t.agentValue !== null && t.benchmarkValue !== null) {
      line += ` — Agent: ${t.agentValue}% vs Peer: ${t.benchmarkValue}%`;
    }
    line += `\n   → _${t.action}_`;
    return line;
  }).join('\n');

  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*${agent.name}* (${agent.site})\n${themeLines}` },
  });
  blocks.push({ type: 'divider' });
}

blocks.push({
  type: 'context',
  elements: [{ type: 'mrkdwn', text: `_Open ROLI → Coaching Digest for full details and clip links_` }],
});

return [{ json: { weekStart, hasThemes: true, agentCount: Object.keys(byAgent).length, blocks: JSON.stringify(blocks) } }];
